declare(strict_types=1);require dirname(__DIR__).'/config/config.php';require dirname(__DIR__).'/vendor/autoload.php';use App\Core\Database;use App\Services\ControlEscaneres\Import\{InitialScannerCsvValidator,LocalFixtureManager};$file=$argv[1]??'';$execute=in_array('--execute',$argv,true);$validate=in_array('--validate-only',$argv,true);$confirm=in_array('--confirm-local',$argv,true)&&in_array('--validation-approved',$argv,true);$interactive=(function_exists('stream_isatty')&&stream_isatty(STDIN))||in_array('--ci-local',$argv,true);$dbArg=null;foreach($argv as$a)if(str_starts_with($a,'--database='))$dbArg=substr($a,11);if($file===''||(!$validate&&!$execute)){fwrite(STDERR,"Uso: php bin/control-escaneres-import.php archivo.csv --validate-only\n");exit(2);}try{$r=(new InitialScannerCsvValidator())->validate($file);echo'[PASS] Validación sin escritura completada. Total='.$r['total'].' válidas='.$r['valid'].' inválidas='.$r['invalid'].PHP_EOL;if($r['invalid'])exit(1);if(!$execute)exit(0);$manager=new LocalFixtureManager();$manager->assertLocal(getenv('APP_ENV')?:'',DB_HOST,DB_NAME,(string)$dbArg,$confirm,$interactive);$loaded=$manager->load(Database::getConnection(),$file);echo'[PASS] Fixtures ficticios insertados='.$loaded['inserted'].'. No se mostraron datos sensibles.'.PHP_EOL;exit(0);}catch(DomainException|InvalidArgumentException$e){fwrite(STDERR,'[BLOCKED] '.$e->getMessage().PHP_EOL);exit(2);}catch(Throwable$e){fwrite(STDERR,"[ERROR] Carga detenida; transacción revertida.\n");exit(3);}
